def pagerank_simplified(graph, damping_factor=0.85, iterations=100):
    all_pages = set()
    for source, targets in graph.items():
        all_pages.add(source)
        for target in targets:
            all_pages.add(target)

    all_pages = sorted(list(all_pages)) # Sort for consistent order, though not strictly necessary
    N = len(all_pages)

    if N == 0:
        return {}

    pageranks = {page: 1.0 / N for page in all_pages}

    # Precompute in_links (what pages link to this page)
    # and out_degrees (how many links this page has) for efficiency
    in_links = {page: [] for page in all_pages}
    out_degrees = {page: 0 for page in all_pages}

    for source, targets in graph.items():
        out_degrees[source] = len(targets)
        for target in targets:
            in_links[target].append(source)

    for _ in range(iterations):
        new_pageranks = {page: (1.0 - damping_factor) / N for page in all_pages}

        # Calculate the total rank of dangling nodes (nodes with no outgoing links)
        dangling_contribution = 0.0
        for page in all_pages:
            if out_degrees[page] == 0:
                dangling_contribution += pageranks[page]

        for page_j in all_pages:
            # Contribution from pages linking to page_j
            sum_of_inbound_rank_contributions = 0.0
            for page_i in in_links[page_j]:
                # Only non-dangling pages contribute through their links
                if out_degrees[page_i] > 0:
                    sum_of_inbound_rank_contributions += pageranks[page_i] / out_degrees[page_i]

            # Add uniform contribution from dangling nodes (they effectively link to all pages)
            sum_of_inbound_rank_contributions += dangling_contribution / N

            new_pageranks[page_j] += damping_factor * sum_of_inbound_rank_contributions

        pageranks = new_pageranks

    return pageranks
